229→function EditSnippetView({ snippet, onSubmit }: EditSnippetViewProps) {
230→  const [form, setForm] = useState<SnippetFormState>(() => {
231→    if (snippet) {
232→      return {
233→        name: snippet.name,
234→        keyword: snippet.keyword,
235→        snippet: snippet.content,
236→        category: snippet.category,
237→        tags: snippet.tags.map(t => t.text.toLowerCase()),
238→      };
239→    }
240→    return INITIAL_SNIPPET_FORM;
241→  });
242→  const [errors, setErrors] = useState<
243→    Partial<Record<keyof SnippetFormState, string>>
244→  >({});
245→
246→  const handleSubmit = useCallback(() => {
247→    const newErrors: Partial<Record<keyof SnippetFormState, string>> = {};
248→    if (!form.name.trim()) {
249→      newErrors.name = 'Name is required';
250→    }
251→    if (!form.snippet.trim()) {
252→      newErrors.snippet = 'Snippet content is required';
253→    }
254→    setErrors(newErrors);
255→    if (Object.keys(newErrors).length > 0) return;
256→    onSubmit(form);
257→  }, [
258→    form,
259→    onSubmit,
260→  ]);
261→
262→  useKeyboardShortcut(
263→    {
264→      key: 'Enter',
265→      meta: true,
266→    },
267→    handleSubmit,
268→  );
269→
270→  return (
271→    <Form onSubmit={handleSubmit}>
272→      <FormTextField
273→        label="Name"
274→        value={form.name}
275→        onChange={v =>
276→          setForm(prev => ({
277→            ...prev,
278→            name: v,
279→          }))
280→        }
281→        placeholder="e.g. Email Signature"
282→        error={errors.name}
283→        autoFocus
284→      />
285→      <FormTextField
286→        label="Keyword"
287→        value={form.keyword}
288→        onChange={v =>
289→          setForm(prev => ({
290→            ...prev,
291→            keyword: v,
292→          }))
293→        }
294→        placeholder="e.g. !sig"
295→        description="Type this to expand the snippet"
296→      />
297→      <FormDropdown
298→        label="Category"
299→        value={form.category}
300→        onChange={v => {
301→          if (isSnippetCategory(v)) {
302→            setForm(prev => ({
303→              ...prev,
304→              category: v,
305→            }));
306→          }
307→        }}
308→        options={FORM_CATEGORY_OPTIONS}
309→        placeholder="Select a category"
310→      />
311→      <FormTagPicker
312→        label="Tags"
313→        value={form.tags}
314→        onChange={v =>
315→          setForm(prev => ({
316→            ...prev,
317→            tags: v,
318→          }))
319→        }
320→        options={FORM_TAG_OPTIONS}
321→        placeholder="Add tags..."
322→        description="Categorize your snippet with tags"
323→      />
324→      <FormTextArea
325→        label="Snippet"
326→        value={form.snippet}
327→        onChange={v =>
328→          setForm(prev => ({
329→            ...prev,
330→            snippet: v,
331→          }))
332→        }
333→        placeholder="Enter your snippet content..."
334→        error={errors.snippet}
335→        rows={5}
336→      />
337→    </Form>
338→  );
339→}
