354→  const { items: hudItems, show: showHUD } = useHUD();
355→  const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();
356→  const now = useMemo(() => new Date(), []);
357→
358→  const filtered = useMemo(() => {
359→    let items = entries;
360→    if (filterValue !== 'all') {
361→      items = items.filter(e => e.category === filterValue);
362→    }
363→    if (query) {
364→      items = items.filter(
365→        e =>
366→          fuzzyMatch(query, e.name) ||
367→          fuzzyMatch(query, e.keyword) ||
368→          fuzzyMatch(query, e.content),
369→      );
370→    }
371→    return items;
372→  }, [
373→    entries,
374→    query,
