405→    return groups;
406→  }, [filtered]);
407→
408→  const flatItems = useMemo(
409→    () => groupedByCategory.flatMap(g => g.items),
410→    [groupedByCategory],
411→  );
412→  const totalItemCount = flatItems.length;
413→
414→  useEffect(() => {
415→    if (totalItemCount === 0) {
416→      setSelectedIndex(0);
417→    } else {
418→      setSelectedIndex(prev =>
419→        prev >= totalItemCount ? totalItemCount - 1 : prev);
420→    }
421→  }, [totalItemCount]);
422→
423→  const selectedEntry = flatItems[selectedIndex];
424→
425→  const handleQueryChange = useCallback((value: string) => {
426→    setQuery(value);
427→    setSelectedIndex(0);
428→    setActionsOpen(false);
429→  }, []);
430→
431→  const handleFilterChange = useCallback((value: string) => {
432→    setFilterValue(value);
433→    setSelectedIndex(0);
434→  }, []);
435→
436→  const handleActiveIndexChange = useCallback((index: number) => {
437→    setSelectedIndex(index);
438→    setActionsOpen(false);
439→  }, []);
440→
441→  const handleInsert = useCallback(() => {
442→    if (!selectedEntry) return;
443→    setActionsOpen(false);
444→    showHUD({
445→      icon: <SnippetHUDIcon />,
446→      title: 'Inserted Snippet',
447→    });
448→  }, [
449→    selectedEntry,
450→    showHUD,
