623→  useKeyboardShortcut(
624→    {
625→      key: 'n',
626→      meta: true,
627→    },
628→    handleCreate,
629→    {
630→      enabled: subView === 'list',
631→    },
632→  );
633→  useKeyboardShortcut(
634→    {
635→      key: 'e',
636→      meta: true,
637→    },
