713→                keys={[
714→                  '⌘',
715→                  '⌫',
716→                ]}
717→              />
718→            ),
719→            onClick: handleDelete,
720→          },
721→        ],
722→      },
723→    ],
724→    [
725→      handleInsert,
726→      handleCopy,
727→      handleEdit,
728→      handleCreate,
729→      handleDelete,
