829→                            key={entry.id}
830→                            index={idx}
831→                            icon={<SnippetHUDIcon />}
832→                            title={entry.name}
833→                            subtitle={truncateContent(entry.content, 50)}
834→                            accessories={[
835→                              ...(entry.keyword
836→                                ? [
837→                                    {
