862→                }
863→
864→                return sections;
865→              })()}
866→            </List>
867→          )}
868→        </div>
869→      </div>
870→      <ActionPanel
871→        contextLabel="Snippets"
872→        actions={[
873→          {
874→            label: 'Insert',
875→            shortcut: <Kbd keys={['↵']} />,
876→          },
877→          {
878→            label: 'Actions',
879→            shortcut: (
880→              <Kbd
881→                keys={[
882→                  '⌘',
883→                  'K',
884→                ]}
