313→        />
314→        <FormDropdown
315→          label="Window Position"
316→          value={settings.windowPosition}
317→          onChange={v => {
318→            onSettingsChange({
319→              ...settings,
320→              windowPosition: v,
321→            });
322→            onWindowPositionChange(v);
323→          }}
324→          options={WINDOW_POSITION_OPTIONS}
325→        />
326→        <FormDropdown
327→          label="Window Width"
