386→function ExtensionRow({
387→  ext,
388→  onToggle,
389→  showAuthor,
390→}: {
391→  ext: ExtensionEntry;
392→  onToggle: (id: string) => void;
393→  showAuthor: boolean;
394→}) {
395→  return (
396→    <div
397→      className="settings-extension"
398→      onClick={() => onToggle(ext.id)}
399→      role="button"
400→      tabIndex={0}
401→      onKeyDown={e => {
402→        if (e.key === 'Enter' || e.key === ' ') {
403→          e.preventDefault();
404→          onToggle(ext.id);
405→        }
406→      }}
407→    >
408→      <div className="settings-extension__icon">{ext.icon()}</div>
409→      <div className="settings-extension__info">
410→        <div className="settings-extension__name">{ext.name}</div>
411→        <div className="settings-extension__meta">
412→          {ext.description}
413→          {showAuthor && <> &middot; {ext.author}</>}
414→        </div>
415→      </div>
416→      <div className="settings-extension__toggle">
417→        <ToggleSwitch
418→          checked={ext.enabled}
419→          onChange={() => onToggle(ext.id)}
420→          label={`Toggle ${ext.name}`}
421→        />
422→      </div>
423→    </div>
424→  );
425→}
426→
427→function ExtensionsTab({
428→  extensions,
429→  onToggle,
430→  query,
431→}: {
432→  extensions: ExtensionEntry[];
433→  onToggle: (id: string) => void;
434→  query: string;
435→}) {
436→  const filtered = useMemo(() => {
437→    if (!query) return extensions;
438→    const lower = query.toLowerCase();
439→    return extensions.filter(
440→      ext =>
441→        ext.name.toLowerCase().includes(lower) ||
442→        ext.description.toLowerCase().includes(lower) ||
443→        ext.author.toLowerCase().includes(lower),
444→    );
445→  }, [
446→    extensions,
447→    query,
448→  ]);
449→
450→  const raycastExts = filtered.filter(ext => ext.author === 'Raycast');
451→  const communityExts = filtered.filter(ext => ext.author !== 'Raycast');
452→
453→  return (
454→    <div className="settings-view__extensions">
455→      {filtered.length === 0 ? (
456→        <EmptyState
457→          icon={<SearchEmptyIcon />}
458→          title="No Extensions Found"
459→          description="Try a different search term"
460→        />
461→      ) : (
462→        <>
463→          {raycastExts.length > 0 && (
464→            <div className="settings-section">
465→              <div className="settings-section__title">Built-in</div>
466→              {raycastExts.map(ext => (
467→                <ExtensionRow
468→                  key={ext.id}
469→                  ext={ext}
470→                  onToggle={onToggle}
471→                  showAuthor={false}
472→                />
473→              ))}
474→            </div>
475→          )}
476→          {communityExts.length > 0 && (
477→            <div className="settings-section">
478→              <div className="settings-section__title">Community</div>
479→              {communityExts.map(ext => (
480→                <ExtensionRow
481→                  key={ext.id}
482→                  ext={ext}
483→                  onToggle={onToggle}
484→                  showAuthor
485→                />
486→              ))}
487→            </div>
488→          )}
489→        </>
490→      )}
491→    </div>
492→  );
493→}
