529→          className="settings-action-row"
530→          onClick={onImport}
531→          role="button"
532→          tabIndex={0}
533→          onKeyDown={e => {
534→            if (e.key === 'Enter' || e.key === ' ') {
535→              e.preventDefault();
536→              onImport();
537→            }
538→          }}
539→        >
540→          <div className="settings-action-row__icon">
541→            <ImportIcon />
542→          </div>
543→          <span className="settings-action-row__label">Import Settings</span>
544→          <span className="settings-action-row__hint">Load from JSON</span>
545→        </div>
